# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import SwiftUI
import UIKit

struct Promo: Equatable {
    let code: String
    let discount: Int
}

final class PromoManager: ObservableObject {
    @Published private(set) var appliedPromo: Promo?
    @Published private(set) var statusMessage: String = "No promo applied"

    func applyPromo(from url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              components.host == "myapp.com",
              components.path == "/promo" else {
            statusMessage = "Invalid promotional link"
            return
        }

        let items = components.queryItems ?? []
        let code = items.first(where: { $0.name == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let discountString = items.first(where: { $0.name == "discount" })?.value ?? ""

        guard !code.isEmpty else {
            statusMessage = "Missing promo code"
            return
        }

        guard let discount = Int(discountString), (1...100).contains(discount) else {
            statusMessage = "Invalid discount percentage"
            return
        }

        let promo = Promo(code: code, discount: discount)
        appliedPromo = promo
        applyToUserAccount(promo)
        statusMessage = "Applied promo \(promo.code) for \(promo.discount)% off"
    }

    private func applyToUserAccount(_ promo: Promo) {
        UserAccountStore.shared.applyPromo(code: promo.code, discount: promo.discount)
    }
}

final class UserAccountStore {
    static let shared = UserAccountStore()

    private let promoCodeKey = "appliedPromoCode"
    private let discountKey = "appliedPromoDiscount"

    private init() {}

    var currentPromo: Promo? {
        let defaults = UserDefaults.standard
        guard let code = defaults.string(forKey: promoCodeKey) else { return nil }
        let discount = defaults.integer(forKey: discountKey)
        guard !code.isEmpty, discount > 0 else { return nil }
        return Promo(code: code, discount: discount)
    }

    func applyPromo(code: String, discount: Int) {
        let defaults = UserDefaults.standard
        defaults.set(code, forKey: promoCodeKey)
        defaults.set(discount, forKey: discountKey)
    }
}

final class AppDelegate: NSObject, UIApplicationDelegate {
    func application(_ application: UIApplication,
                     continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let incomingURL = userActivity.webpageURL else {
            return false
        }

        PromoLinkRouter.shared.handle(url: incomingURL)
        return true
    }
}

final class PromoLinkRouter {
    static let shared = PromoLinkRouter()

    private init() {}

    weak var promoManager: PromoManager?

    func handle(url: URL) {
        promoManager?.applyPromo(from: url)
    }
}

struct ContentView: View {
