@main
struct PromoCampaignApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
    @StateObject private var promoManager = PromoManager()

    init() {
        if let existing = UserAccountStore.shared.currentPromo {
            let manager = PromoManager()
            manager.applyPromo(from: URL(string: "https://myapp.com/promo?code=\(existing.code)&discount=\(existing.discount)")!)
        }
    }

    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(promoManager)
                .onAppear {
                    PromoLinkRouter.shared.promoManager = promoManager
                    if let existing = UserAccountStore.shared.currentPromo, promoManager.appliedPromo == nil {
                        promoManager.statusMessage = "Applied promo \(existing.code) for \(existing.discount)% off"
                    }
                }
        }
    }
}